<script lang="ts">
  const html: string = "<h1>Collection List Item</h1>\n\n<p>A collection list item is one entry in a <code>collection-list</code>, presenting a required heading plus optional thumbnail image, meta line (date, category), and short description.</p>\n\n<p>Use it inside <code>CollectionList</code> to render homogeneous summary cards for articles, events, search results, or news entries.</p>\n\n<h2>Implementation Notes</h2>\n\n<ul>\n<li>Renders a native <code>&lt;li&gt;</code> element with class <code>collection-list-item</code></li>\n<li><code>heading</code> prop is <strong>required</strong> — it is rendered as an <code>&lt;h3&gt;</code> heading inside the item</li>\n<li>When <code>href</code> is provided, the heading text is wrapped in an <code>&lt;a&gt;</code> element</li>\n<li>Optional <code>imageUrl</code> + <code>imageAlt</code> render a leading <code>&lt;img&gt;</code> thumbnail</li>\n<li>Optional <code>meta</code> renders a meta paragraph (e.g., date or category)</li>\n<li>Optional <code>description</code> renders a body paragraph</li>\n<li>Optional <code>children</code> render after the description for custom extra content</li>\n<li>Optional <code>label</code> sets <code>aria-label</code> to override the default accessible name</li>\n</ul>\n\n<h2>Composition</h2>\n\n<p>This component is part of the <code>*List</code> <code>*ListItem</code> composition pattern. It must be a child of <code>CollectionList</code>.</p>\n\n<h2>Props</h2>\n\n<ul>\n<li><code>heading</code>: string (<strong>required</strong>) -- item heading text</li>\n<li><code>meta</code>: string (optional) -- meta line such as a date or category</li>\n<li><code>description</code>: string (optional) -- body description text</li>\n<li><code>imageUrl</code>: string (optional) -- thumbnail image src</li>\n<li><code>imageAlt</code>: string (optional) -- thumbnail image alt text</li>\n<li><code>href</code>: string (optional) -- when provided, the heading is wrapped in an <code>&lt;a&gt;</code></li>\n<li><code>label</code>: string (optional) -- aria-label override</li>\n<li><code>children</code>: slot -- additional content rendered after the description</li>\n<li><code>...restProps</code>: any additional HTML attributes</li>\n</ul>\n\n<h2>Usage</h2>\n\n<p>Article entry with link, meta, and description:</p>\n\n<pre><code class=\"language-html\">&lt;CollectionListItem\n  heading=\"Plain language is for everyone\"\n  href=\"/blog/plain-language\"\n  meta=\"Published Jan 5, 2025\"\n  description=\"A short overview of why plain language matters in public services.\"\n/&gt;</code></pre>\n\n<p>Event entry with thumbnail:</p>\n\n<pre><code class=\"language-html\">&lt;CollectionListItem\n  heading=\"Annual conference\"\n  imageUrl=\"/img/conf.jpg\"\n  imageAlt=\"Speaker on stage\"\n  meta=\"May 12, 2025\"\n/&gt;</code></pre>\n\n<h2>Keyboard Interactions</h2>\n\n<ul>\n<li>Tab: moves focus to the heading link (when <code>href</code> is provided) or to descendants</li>\n<li>All key handling is delegated to the contained interactive elements</li>\n</ul>\n\n<h2>ARIA</h2>\n\n<ul>\n<li>Implicit <code>listitem</code> role from <code>&lt;li&gt;</code> element</li>\n<li><code>aria-label</code> is rendered when <code>label</code> is supplied</li>\n<li>Image <code>alt</code> attribute provides the image's accessible text</li>\n</ul>\n\n<h2>When to Use</h2>\n\n<ul>\n<li>Use as a child of <code>CollectionList</code> to render an entry in a homogeneous list.</li>\n<li>Use when each entry has a heading and optional supporting information.</li>\n<li>Use when the heading should optionally link to a detail page.</li>\n</ul>\n\n<h2>When Not to Use</h2>\n\n<ul>\n<li>Do not use outside a <code>CollectionList</code>.</li>\n<li>Do not use for tabular data — use <code>DataTableRow</code> instead.</li>\n<li>Do not use for navigation list items — use the appropriate <code>*ListItem</code> for the navigation.</li>\n</ul>\n\n<h2>Headless</h2>\n\n<p>Renders the structural skeleton — <code>&lt;li&gt;</code> with optional <code>&lt;img&gt;</code>, <code>&lt;h3&gt;</code>, <code>&lt;p class=\"...-meta\"&gt;</code>, <code>&lt;p class=\"...-description\"&gt;</code>, and slot. Visual spacing, image dimensions, and typography are entirely the consumer's responsibility.</p>\n\n<h2>Styles</h2>\n\n<p>Consumer CSS targets the <code>collection-list-item</code> class plus the inner <code>collection-list-item-image</code>, <code>collection-list-item-heading</code>, <code>collection-list-item-meta</code>, and <code>collection-list-item-description</code> classes for fine-grained control.</p>\n\n<h2>Testing</h2>\n\n<ul>\n<li>Verify the component renders an <code>&lt;li&gt;</code> element with class <code>collection-list-item</code></li>\n<li>Verify the heading text appears inside an <code>&lt;h3&gt;</code> element</li>\n<li>Verify the heading is wrapped in an <code>&lt;a&gt;</code> when <code>href</code> is provided</li>\n<li>Verify the heading is plain text when <code>href</code> is omitted</li>\n<li>Verify the image renders only when <code>imageUrl</code> is provided</li>\n<li>Verify the meta paragraph renders only when <code>meta</code> is provided</li>\n<li>Verify the description paragraph renders only when <code>description</code> is provided</li>\n<li>Verify children render after the description when supplied</li>\n<li>Verify additional HTML attributes pass through to the root <code>&lt;li&gt;</code></li>\n</ul>\n\n<h2>Advice</h2>\n\n<ul>\n<li><strong>Designers</strong>: Keep heading length predictable so the list reads as a tidy stack. Use thumbnails sparingly and at consistent dimensions.</li>\n<li><strong>Developers</strong>: Always supply <code>imageAlt</code> when <code>imageUrl</code> is set. Use <code>href</code> to make the heading the link target so the entire heading text is announced as the link.</li>\n</ul>\n\n<h2>Related components</h2>\n\n<ul>\n<li><code>collection-list</code> — a compact list of multiple related items such as articles or events</li>\n</ul>\n\n<h2>References</h2>\n\n<ul>\n<li>US Web Design System Collection: https://designsystem.digital.gov/components/collection/</li>\n<li>HTML <code>&lt;li&gt;</code>: https://developer.mozilla.org/en-US/docs/Web/HTML/Element/li</li>\n<li>WCAG 1.1.1 Non-text Content: https://www.w3.org/WAI/WCAG22/Understanding/non-text-content</li>\n</ul>";
  // BEGIN auto-generated component example consts
  const demoHtml: string = "<div class=\"collection-list-item\" aria-label=\"one item in a collection list with optional image, heading, meta, and description\">CollectionListItem</div>";
  const svelteSource: string = "// In your Svelte component:\nimport CollectionListItem from \"lily-design-system-svelte-headless/components/CollectionListItem/CollectionListItem.svelte\";\n\n<CollectionListItem>\n  <!-- CollectionListItem content -->\n</CollectionListItem>\n";
  // END auto-generated component example consts
